import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import API_BASE from '../config';
import { sendRoundDataToCaptivate, sendPlayerAndWinnerDataToCaptivate, getColorForRarity } from '../utils/sendRoundDataToCaptivate';
import { getVeeFriendsLogoHeader } from '../utils/imageUtils';
import { useVeeFriendsTheme, createFlexContainer } from '../theme/VeeFriendsTheme';

function ProducerDashboard() {
  console.log('ProducerDashboard mounted');

  const [player1Email, setPlayer1Email] = useState('');
  const [player2Email, setPlayer2Email] = useState('');
  const [player1Decks, setPlayer1Decks] = useState([]);
  const [player2Decks, setPlayer2Decks] = useState([]);
  const [selectedDeck1, setSelectedDeck1] = useState(null);
  const [selectedDeck2, setSelectedDeck2] = useState(null);
  const [gameId, setGameId] = useState('');
  const [gameState, setGameState] = useState(null);
  const [loadGameId, setLoadGameId] = useState('');
  const [lastCaptivateData, setLastCaptivateData] = useState(null);
  const [lastPlayerData, setLastPlayerData] = useState(null);
  const [showAdminEdit, setShowAdminEdit] = useState(false);

  const lastRoundIdRef = useRef(null);
  const navigate = useNavigate();

  // Use the centralized theme
  const { theme, baseStyles } = useVeeFriendsTheme();

  // Component-specific styles that extend the base styles
  const styles = {
    ...baseStyles,
    container: {
      ...baseStyles.container,
      padding: '2rem',
      maxWidth: '1000px',
      margin: '0 auto'
    },
    header: {
      ...baseStyles.header,
      textAlign: 'center',
      marginBottom: '2rem'
    },
    headerLine1: {
      fontSize: '2.5rem',
      color: theme.colors.gold,
      fontWeight: 'bold',
      marginBottom: '0.25rem'
    },
    headerLine2: {
      fontSize: '2.5rem',
      fontWeight: 'bold',
      color: theme.colors.gold,
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '1rem'
    },
    logo: {
      height: '60px',
      width: 'auto'
    },
    playerSection: {
      ...baseStyles.section,
      display: 'flex',
      flexDirection: 'column',
      gap: '1rem',
      marginBottom: '2rem',
      padding: '1.5rem',
      border: `2px solid ${theme.colors.subtleBorder}`,
      borderRadius: theme.borderRadius.lg,
      backgroundColor: theme.colors.darkPurple
    },
    playerHeader: {
      ...baseStyles.sectionTitle,
      fontSize: '1.3rem',
      marginBottom: '1rem',
      color: theme.colors.gold,
      display: 'flex',
      alignItems: 'center',
      gap: '0.5rem'
    },
    inputRow: {
      display: 'flex',
      gap: '1rem',
      alignItems: 'flex-end',
      flexWrap: 'wrap'
    },
    gameControlSection: {
      ...baseStyles.section,
      textAlign: 'center',
      padding: '2rem',
      border: `2px solid ${theme.colors.green}`,
      borderRadius: theme.borderRadius.lg,
      backgroundColor: theme.colors.darkGreen,
      marginBottom: '2rem'
    },
    gameStatusSection: {
      ...baseStyles.section,
      padding: '1.5rem',
      border: `2px solid ${theme.colors.subtleBorder}`,
      borderRadius: theme.borderRadius.lg,
      backgroundColor: theme.colors.darkPurple,
      marginBottom: '2rem'
    },
    loadGameSection: {
      ...baseStyles.section,
      padding: '1.5rem',
      border: `2px solid ${theme.colors.subtleBorder}`,
      borderRadius: theme.borderRadius.lg,
      backgroundColor: theme.colors.darkPurple,
      marginBottom: '2rem'
    },
    captivateSection: {
      ...baseStyles.section,
      padding: '1.5rem',
      border: `2px solid ${theme.colors.subtleBorder}`,
      borderRadius: theme.borderRadius.lg,
      backgroundColor: theme.colors.darkPurple
    },
    startGameButton: {
      ...baseStyles.submitButton,
      fontSize: '1.2rem',
      padding: '1rem 2rem',
      margin: '1rem'
    },
    gameIdDisplay: {
      fontSize: '1.1rem',
      fontWeight: 'bold',
      color: theme.colors.gold,
      margin: '1rem 0',
      textTransform: 'none'
    },
